  testWidgets('renders readiness dashboard tiles', (tester) async {
    const l10n = AppLocalizations(Locale('en'));
    final session = GameSession(
      id: '1',
      name: 'Session',
      date: '25.06.26',
      c1: 2,
      c2: 2,
      tries: 1,
      total: 4,
      matchDuration: '01:00:00',
      grid: [
        {'type': 1, 'status': 'green', 'interval': 60, 'target': 60},
